import React, { useEffect, useState } from "react";
import axios from "axios";
import { startTracking, getData } from "./tracker";

const questions = [
  { prompt: "A is for _", answer: "apple" },
  { prompt: "B is for _", answer: "ball" },
  { prompt: "C is for _", answer: "cat" },
];

function LetterGame({ onNext }) {
  const [answers, setAnswers] = useState(Array(questions.length).fill(""));
  const [status, setStatus] = useState("");

  useEffect(() => {
    startTracking();
  }, []);

  const handleChange = (index, value) => {
    const next = [...answers];
    next[index] = value;
    setAnswers(next);
  };

  const finishGame = async () => {
    const isCorrect = questions.every(
      (q, i) => q.answer.toLowerCase() === answers[i].trim().toLowerCase()
    );

    if (!isCorrect) {
      setStatus("Please try again — check the spelling and fill in every blank.");
      return;
    }

    setStatus("Great job! Saving progress...");

    const data = getData();

    try {
      await axios.post("http://localhost:5000/save", {
        studentId: "child_01",
        activity: "letter_fill_in_the_blank",
        answers,
        ...data,
      });
    } catch (err) {
      console.error("LetterGame save failed:", err);
      alert("Progress could not be saved to the server. Continuing anyway.");
    }

    if (onNext) onNext();
  };

  const style = {
    textAlign: "center",
    backgroundColor: "#FFE4E1",
    height: "100vh",
    paddingTop: "50px",
  };

  return (
    <div style={style}>
      <h1>Fill in the blanks ✏️</h1>
      <p style={{ fontSize: "18px" }}>Complete each sentence with the missing word.</p>

      <div style={{ maxWidth: "420px", margin: "0 auto", textAlign: "left" }}>
        {questions.map((question, index) => (
          <div key={index} style={{ marginBottom: "18px" }}>
            <label style={{ display: "block", fontSize: "20px", marginBottom: "8px" }}>
              {question.prompt}
            </label>
            <input
              type="text"
              value={answers[index]}
              onChange={(e) => handleChange(index, e.target.value)}
              style={{
                width: "100%",
                padding: "10px",
                fontSize: "18px",
                borderRadius: "8px",
                border: "1px solid #ccc",
              }}
            />
          </div>
        ))}
      </div>

      {status && (
        <p style={{ color: status.includes("Great") ? "green" : "red", fontWeight: 600 }}>
          {status}
        </p>
      )}

      <button onClick={finishGame} style={{ fontSize: "20px", marginTop: "20px" }}>
        Submit Answers
      </button>
    </div>
  );
}

export default LetterGame;
